import {chromium,webkit} from 'playwright';
import fs from 'node:fs';
import assert from 'node:assert/strict';
import {fileURLToPath} from 'node:url';
const browserName=process.env.BROWSER||'chromium',browserType={chromium,webkit}[browserName];
if(!browserType)throw new Error(`Ukjent BROWSER: ${browserName}`);
const out=process.env.QA_OUT||fileURLToPath(new URL('./qa',import.meta.url));fs.mkdirSync(out,{recursive:true});
const browser=await browserType.launch({headless:true});
const page=await browser.newPage({viewport:{width:1280,height:900},deviceScaleFactor:1});
const errors=[];page.on('pageerror',e=>errors.push('pageerror: '+e.message));page.on('console',m=>{if(m.type()==='error')errors.push('console: '+m.text());});page.on('response',r=>{if(r.status()>=400)errors.push(`http ${r.status()}: ${r.url()}`);});
const base=process.env.BASE_URL||'http://127.0.0.1:8770/';
